w:r.w:t:
s1 = servo(a,"D9");
s2 = servo(a,"D10");
s3 = servo(a,"D11");
s4 = servo(a,"D12");

% neutral
writePosition(s1,0.5);
writePosition(s2,0.5);
writePosition(s3,0.5);
writePosition(s4,0.5);
pause(1);

% same positions as your Arduino IDE sketch
writePosition(s1,30/180);
writePosition(s2,60/180);
writePosition(s3,120/180);
writePosition(s4,150/180);
pause(1);

% back to neutral
writePosition(s1,0.5);
writePosition(s2,0.5);
writePosition(s3,0.5);
writePosition(s4,0.5);
pause(1);
